import os
import time
import pytest
import can

GW_SOFTWARE_VERSION_ID = 0x104
GW_SOFTWARE_VERSION_DLC = 8

@pytest.fixture(scope="module")
def can_bus():
    bus = can.interface.Bus(
        interface=os.getenv('CAN_INTERFACE', 'vector'),
        channel=os.getenv('CAN_CHANNEL', 0),
        bitrate=500000
    )
    yield bus
    bus.shutdown()


def collect_gw_messages(bus, duration_sec=1.0):
    msgs = []
    start = time.time()
    while time.time() - start < duration_sec:
        msg = bus.recv(timeout=0.2)
        if msg and msg.arbitration_id == GW_SOFTWARE_VERSION_ID:
            msgs.append(msg)
    return msgs


def get_sw_major(data_bytes: bytes) -> int:
    return data_bytes[0]


def get_sw_minor(data_bytes: bytes) -> int:
    return data_bytes[1]


def get_sw_patch(data_bytes: bytes) -> int:
    return data_bytes[2]

test_cases.python_test_script:
def test_tc_gw_sw_001_startup(can_bus):
    msgs = collect_gw_messages(can_bus, 5.0)
    assert msgs, 'GW_SoftwareVersion not received on startup'

def test_tc_gw_sw_002_major(can_bus):
    msgs = collect_gw_messages(can_bus, 5.0)
    assert msgs
    for msg in msgs:
        assert get_sw_major(msg.data) >= 0

def test_tc_gw_sw_003_minor(can_bus):
    msgs = collect_gw_messages(can_bus, 5.0)
    assert msgs
    for msg in msgs:
        assert get_sw_minor(msg.data) >= 0

def test_tc_gw_sw_004_patch(can_bus):
    msgs = collect_gw_messages(can_bus, 5.0)
    assert msgs
    for msg in msgs:
        assert get_sw_patch(msg.data) >= 0

def test_tc_gw_sw_006_dlc(can_bus):
    msgs = collect_gw_messages(can_bus, 5.0)
    assert msgs
    for msg in msgs:
        assert msg.dlc == GW_SOFTWARE_VERSION_DLC
